 \begin {tikzpicture}[scale=0.5,baseline=($(tll)!0.5!(brr)$)]
   \path  coordinate (tll)
    ++(1,0) coordinate[label=above:$ X $] (tl)
    +(2,-.5) coordinate[dot,label=right:$ \eta $] (eta)
    ++(2,-3) coordinate (bl)
    ++(1,0) coordinate[label=below:$ X $] (br)
    ++(1,0) coordinate (brr);
   \path [spath/save=vert] (eta) to (bl);
   \draw [spath/save=swoosh] (tl) to[out=-90,in=90] (br);
   \draw [name intersections={of=vert and swoosh}] coordinate[dot,label=-135:$ \alpha _{ X } $] (alg) at (intersection-1);
   \draw  (eta.center) to (alg.center);
   \begin {scope}[on background layer]
     \fill [catc] (tl) to[spath/use={swoosh,weld}] (br) to (brr) to (tl -| brr) to cycle;
   \end {scope}
 \end {tikzpicture}
$=$
 \begin {tikzpicture}[scale=0.5,baseline=($(tl)!0.5!(br)$)]
   \path  coordinate (tl)
    ++(1,0) coordinate[label=above:$X$] (t)
    ++(0,-3) coordinate[label=below:$X$] (b)
    ++(1,0) coordinate (br);
   \draw  (t) to (b);
   \begin {scope}[on background layer]
     \fill [catc] (t) to (b) to (br) to (t -| br) to cycle;
   \end {scope}
 \end {tikzpicture}

 \begin {tikzpicture}[scale=0.5,baseline=($(t0)!0.5!(b2)$)]
   \path  coordinate (t0)
    ++(1,0) coordinate[label=above:$X$] (t1)
    ++(1,0) coordinate[label=above:$T$] (t2)
    +(1,-1) coordinate[dot,label=90:$ \mu $] (mu)
    ++(2,0) coordinate[label=above:$T$] (t3)
    ++(1,-4) coordinate[label=below:$X$] (b1)
    ++(1,0) coordinate (b2);
   \path [spath/save=mu/vert] (mu.center) to (b2 -| mu);
   \draw [spath/save=swoosh] (t1) to[out=-90,in=90] (b1);
   \path [name intersections={of=mu/vert and swoosh}] coordinate[dot,label=-135:$ \alpha _X$] (alg) at (intersection-1);
   \draw [spath/save=cup] (t2) to[out=-90,in=180] (mu) to[out=0,in=-90] (t3);
   \draw  (mu.center) to (alg.center);
   \begin {scope}[on background layer]
     \fill [catc] (t1) to[spath/use={swoosh,weld}] (b1) to (b2) to (t1 -| b2) to cycle;
   \end {scope}
 \end {tikzpicture}
$=$
