   coordinate (nw)
   ++(1,0) coordinate[label=above:$ X $] (n/X)
   ++(3,-3) coordinate[label=below:$ X $] (s/X)
   ++(1,0) coordinate (se)
 ;
  \draw [spath/save=swoosh] (n/X) to[out=-90,in=90] (s/X);
  \path 
   coordinate[dot,label=below:$x$] (suc) at (spath cs:swoosh 0.33)
   coordinate[dot,label=below:$ \alpha _{ X } $] (alg) at (spath cs:swoosh 0.6)
   coordinate[label=above:$ F $] (n/F) at (nw -| alg)
 ;
  \draw  (n/F) to (alg.center);
  \begin {scope}[on background layer]
    \fill [catc] (n/X) to[spath/use={swoosh,weld}] (s/X) to (se) to (nw -| se) to cycle;
  \end {scope}
\end {tikzpicture}

mainmatter.p:
Let \mathbb {T} be a monad on a category \mathcal {C}, and let X be a weak algebra for \mathbb {T} that is a fixed point, i.e. the algebra map is invertible by { X } \xrightarrow {{ \pi _{ X } }}{ T X }. We may define the induced \mathbb {T}-algebra \bar { X } to have the same carrier object as X and with the algebra map { T X } \xrightarrow {{ \alpha _{ \bar { X } } }}{ X } defined as follows:






    \usepackage {string-diagrams,preamble}

     \begin {tikzpicture}[scale=0.5]
       \path 
        coordinate (nw)
        ++(1,0) coordinate[label=above:$ X $] (n/X)
        ++(5,-4) coordinate[label=below:$ X $] (s/X)
        ++(1,0) coordinate (se);
       \draw [spath/save=wire] (n/X) to[out=-90,in=90] (s/X);
       \path 
        coordinate[dot,label=left:$ \pi _{ X } $] (pi) at (spath cs:wire 0.15)
        coordinate[dot,label=-135:$ \alpha _{ X } $] (alg) at (spath cs:wire 0.8)
        coordinate[label=above:$ T $] (n/T) at (nw -| alg)
      ;
       \draw [spath/save=vert] (alg) to (n/T);
       \path  coordinate[dot,label=right:$ \mu $] (mu) at (spath cs:vert 0.4);
       \draw  (pi.center) to (mu.center);
       \begin {scope}[on background layer]
         \fill [catc] (n/X) to[spath/use={wire,weld}] (s/X) to (se) to (nw -| se) to cycle;
       \end {scope}
     \end {tikzpicture}

